import React, { useEffect, useState } from 'react';
import './MusicNav.css';

const MusicNav: React.FC = () => {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 60);
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const scrollTo = (id: string) => {
    setMenuOpen(false);
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <nav className={`music-nav${scrolled ? ' scrolled' : ''}`}>
      <div className="music-nav-inner">
        <a href="#/" className="nav-logo" onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}>
          <img src="/DEWPOINT_LOGO_white.png" alt="Dewpoint" />
        </a>

        <ul className={`nav-links${menuOpen ? ' open' : ''}`}>
          <li><button onClick={() => scrollTo('bio')}>About</button></li>
          <li><button onClick={() => scrollTo('releases')}>Music</button></li>
          <li><button onClick={() => scrollTo('tour')}>Tour</button></li>
          <li><button onClick={() => scrollTo('photos')}>Photos</button></li>
          <li><a className="nav-epk-btn" href="#/epk" onClick={() => setMenuOpen(false)}>EPK</a></li>
          <li><a className="nav-epk-btn" href="#/resume" onClick={() => setMenuOpen(false)}>Professional Resume</a></li>
        </ul>

        <button
          className={`hamburger${menuOpen ? ' open' : ''}`}
          onClick={() => setMenuOpen(m => !m)}
          aria-label="Toggle menu"
          aria-expanded={menuOpen}
        >
          <span />
          <span />
          <span />
        </button>
      </div>
    </nav>
  );
};

export default MusicNav;
