import React, { useEffect, useState } from 'react';
import './TourCalendar.css';

interface Show {
  id: number;
  date: string;
  venue: string;
  city: string;
  state: string;
  ticketUrl: string;
  thumbnail?: string;
  status: 'upcoming' | 'past';
}

function formatDate(dateStr: string): string {
  const d = new Date(dateStr + 'T00:00:00');
  return new Intl.DateTimeFormat('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  }).format(d);
}

const TourCalendar: React.FC = () => {
  const [shows, setShows] = useState<Show[]>([]);

  useEffect(() => {
    fetch('/shows.json')
      .then(r => (r.ok ? r.json() : []))
      .then(setShows)
      .catch(() => {});
  }, []);

  const upcoming = shows.filter(s => s.status === 'upcoming');

  return (
    <section className="tour-calendar section" id="tour">
      <div className="container">
        <h2 className="section-title tour-title">Tour Dates</h2>

        <div className="shows-list">
          {upcoming.length === 0 ? (
            <div className="shows-empty">
              No upcoming shows announced — check back soon.
            </div>
          ) : (
            upcoming.map(show => (
              <div className={`show-row${show.thumbnail ? ' has-thumbnail' : ''}`} key={show.id}>
                {show.thumbnail && (
                  <div className="show-thumbnail">
                    <img src={`/${show.thumbnail}`} alt={`${show.venue} flyer`} loading="lazy" />
                  </div>
                )}
                <div className="show-date">{formatDate(show.date)}</div>
                <div className="show-venue">
                  <span className="show-venue-name">{show.venue}</span>
                  <span className="show-location">
                    {show.city}{show.state ? `, ${show.state}` : ''}
                  </span>
                </div>
                <div className="show-actions">
                  {show.ticketUrl && (
                    <a
                      href={show.ticketUrl}
                      className="ticket-btn"
                      target="_blank"
                      rel="noopener noreferrer"
                    >
                      Tickets
                    </a>
                  )}
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </section>
  );
};

export default TourCalendar;
