import React from 'react';
import './Footer.css';

const Footer: React.FC = () => {
  const currentYear = new Date().getFullYear();

  const scrollToTop = () => {
    window.scrollTo({
      top: 0,
      behavior: 'smooth'
    });
  };

  return (
    <footer className="footer">
      <div className="container">
        <div className="footer-content">
          <div className="footer-section">
            <h3>Dewpoint</h3>
            <p>Electronic music producer crafting immersive drum &amp; bass, breakbeat, and jungle soundscapes.</p>
          </div>

          <div className="footer-section">
            <h4>Quick Links</h4>
            <ul className="footer-links">
              <li><button onClick={() => document.getElementById('home')?.scrollIntoView({ behavior: 'smooth' })}>Home</button></li>
              <li><button onClick={() => document.getElementById('bio')?.scrollIntoView({ behavior: 'smooth' })}>About</button></li>
              <li><button onClick={() => document.getElementById('releases')?.scrollIntoView({ behavior: 'smooth' })}>Music</button></li>
              <li><button onClick={() => document.getElementById('tour')?.scrollIntoView({ behavior: 'smooth' })}>Tour</button></li>
              <li><button onClick={() => document.getElementById('photos')?.scrollIntoView({ behavior: 'smooth' })}>Photos</button></li>
            </ul>
          </div>

<div className="footer-section">
            <h4>Contact</h4>
            <div className="footer-contact">
              <p><i className="fas fa-envelope"></i> anthony@dewpoint.live</p>
            </div>
          </div>
        </div>

        <div className="footer-bottom">
          <div className="footer-bottom-content">
            <p>&copy; {currentYear} Dewpoint. All rights reserved.</p>
            <button className="scroll-to-top" onClick={scrollToTop} aria-label="Scroll to top">
              <i className="fas fa-arrow-up"></i>
            </button>
          </div>
        </div>
      </div>
    </footer>
  );
};

export default Footer; 