import React, { useEffect, useState } from 'react';
import './Releases.css';

interface ReleaseLinks {
  soundcloud?: string;
  bandcamp?: string;
  spotify?: string;
  submithub?: string;
}

interface Release {
  id: number;
  title: string;
  year: number;
  type: string;
  coverArt: string;
  links: ReleaseLinks;
  featured?: boolean;
}

function PlatformIcon({ platform, url }: { platform: string; url: string }) {
  const icons: Record<string, string> = {
    soundcloud: 'fab fa-soundcloud',
    bandcamp: 'fab fa-bandcamp',
    spotify: 'fab fa-spotify',
    submithub: 'fas fa-external-link-alt',
  };
  const labels: Record<string, string> = {
    soundcloud: 'SoundCloud',
    bandcamp: 'Bandcamp',
    spotify: 'Spotify',
    submithub: 'Listen',
  };
  if (!url) return null;
  return (
    <a
      href={url}
      className={`platform-link platform-${platform}`}
      target="_blank"
      rel="noopener noreferrer"
      aria-label={labels[platform] ?? platform}
    >
      <i className={icons[platform] ?? 'fas fa-music'} aria-hidden="true" />
      <span>{labels[platform] ?? platform}</span>
    </a>
  );
}

const Releases: React.FC = () => {
  const [releases, setReleases] = useState<Release[]>([]);

  useEffect(() => {
    fetch('/releases.json')
      .then(r => (r.ok ? r.json() : []))
      .then(setReleases)
      .catch(() => {});
  }, []);

  const featured = releases.find(r => r.featured);
  const rest = releases.filter(r => !r.featured);

  return (
    <section className="releases section" id="releases">
      <div className="container">
        <h2 className="section-title releases-title">Music &amp; Releases</h2>

        {featured && (
          <div className="featured-release">
            <div className="featured-cover-wrap">
              <img
                src={`/${featured.coverArt}`}
                alt={featured.title}
                className="featured-cover"
                loading="lazy"
              />
            </div>
            <div className="featured-info">
              <span className="release-type-badge">{featured.type}</span>
              <h3 className="featured-title">{featured.title}</h3>
              <p className="featured-year">{featured.year}</p>
              <div className="platform-links">
                {Object.entries(featured.links).map(([platform, url]) => (
                  <PlatformIcon key={platform} platform={platform} url={url as string} />
                ))}
                {Object.values(featured.links).every(v => !v) && (
                  <p className="coming-soon">Streaming links coming soon</p>
                )}
              </div>
            </div>
          </div>
        )}

        {rest.length > 0 && (
          <div className="releases-grid">
            {rest.map(release => {
              const primaryLink = Object.entries(release.links).find(([, url]) => url)?.[0];
              const primaryUrl = primaryLink ? (release.links as Record<string, string>)[primaryLink] : '';
              return (
                <div className="release-card" key={release.id}>
                  <div className="release-cover-wrap">
                    {release.coverArt ? (
                      <img
                        src={`/${release.coverArt}`}
                        alt={release.title}
                        className="release-cover"
                        loading="lazy"
                      />
                    ) : (
                      <div className="release-cover-placeholder">
                        <i className="fab fa-soundcloud" aria-hidden="true" />
                      </div>
                    )}
                    <div className="release-cover-overlay">
                      <div className="platform-links overlay-links">
                        {Object.entries(release.links).map(([platform, url]) => (
                          <PlatformIcon key={platform} platform={platform} url={url as string} />
                        ))}
                      </div>
                    </div>
                  </div>
                  <div className="release-meta">
                    <span className="release-type-badge">{release.type}</span>
                    <h3 className="release-title">
                      {primaryUrl ? (
                        <a href={primaryUrl} target="_blank" rel="noopener noreferrer" className="release-title-link">
                          {release.title}
                        </a>
                      ) : release.title}
                    </h3>
                    <p className="release-year">{release.year}</p>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </section>
  );
};

export default Releases;
