import React, { useState } from 'react';
import './TouchDesigner.css';

const TouchDesigner: React.FC = () => {
  const [inputUrl, setInputUrl] = useState('');
  const [activeUrl, setActiveUrl] = useState('');
  const [popupRef, setPopupRef] = useState<Window | null>(null);

  const connect = () => {
    let url = inputUrl.trim();
    if (!url) return;
    if (!/^https?:\/\//i.test(url)) url = 'https://' + url;
    setActiveUrl(url);
  };

  const disconnect = () => {
    popupRef?.close();
    setPopupRef(null);
    setActiveUrl('');
  };

  const handleKey = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') connect();
  };

  const openPopup = () => {
    const w = window.screen.width;
    const h = window.screen.height;
    const popup = window.open(activeUrl, 'td-notes', `width=${w},height=${h},left=0,top=0`);
    setPopupRef(popup);
  };

  return (
    <div className="td-page">
      <div className="td-topbar">
        <span className="td-topbar-label">TouchDesigner Notes</span>
        <div className="td-topbar-conn">
          <input
            className="td-topbar-input"
            type="text"
            placeholder="https://xxxx.ngrok.io"
            value={inputUrl}
            onChange={e => setInputUrl(e.target.value)}
            onKeyDown={handleKey}
            disabled={!!activeUrl}
            spellCheck={false}
          />
          {!activeUrl
            ? <button className="td-topbar-btn connect" onClick={connect}>Connect</button>
            : <button className="td-topbar-btn disconnect" onClick={disconnect}>Disconnect</button>
          }
        </div>
        {activeUrl && (
          <span className="td-topbar-status">
            <span className="td-dot" /> Ready
          </span>
        )}
      </div>

      {!activeUrl && (
        <div className="td-splash">
          <div className="td-splash-card">
            <h2>TouchDesigner Notes</h2>
            <p>Enter your ngrok URL above to connect to the notes app running in TouchDesigner.</p>
            <ol className="td-steps">
              <li>Open the notes <code>.tox</code> in TouchDesigner</li>
              <li>Note the port number on the Web Server DAT inside it</li>
              <li>
                In PowerShell, run:
                <pre>ngrok http [port]</pre>
              </li>
              <li>Paste the <code>https://xxxx.ngrok.io</code> URL above and click Connect</li>
            </ol>
          </div>
        </div>
      )}

      {activeUrl && (
        <div className="td-launch">
          <div className="td-launch-card">
            <div className="td-launch-icon">📓</div>
            <h2>Notes App Ready</h2>
            <p className="td-launch-url">{activeUrl}</p>
            <button className="td-launch-btn" onClick={openPopup}>
              Open Notes
            </button>
            <p className="td-launch-hint">
              Opens in a fullscreen popup window.<br />
              If ngrok shows a warning page, click <strong>Visit Site</strong> to continue.
            </p>
          </div>
        </div>
      )}
    </div>
  );
};

export default TouchDesigner;
