import React, { useEffect, useState, useCallback } from 'react';
import './PhotoGallery.css';

interface Photo {
  id: number;
  src: string;
  alt: string;
  caption: string;
}

const PhotoGallery: React.FC = () => {
  const [photos, setPhotos] = useState<Photo[]>([]);
  const [lightboxIdx, setLightboxIdx] = useState<number | null>(null);

  useEffect(() => {
    fetch('/photos.json')
      .then(r => (r.ok ? r.json() : []))
      .then(setPhotos)
      .catch(() => {});
  }, []);

  const closeLightbox = () => setLightboxIdx(null);

  const prevPhoto = useCallback(() => {
    setLightboxIdx(i => (i !== null ? (i - 1 + photos.length) % photos.length : null));
  }, [photos.length]);

  const nextPhoto = useCallback(() => {
    setLightboxIdx(i => (i !== null ? (i + 1) % photos.length : null));
  }, [photos.length]);

  useEffect(() => {
    if (lightboxIdx === null) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') closeLightbox();
      if (e.key === 'ArrowLeft') prevPhoto();
      if (e.key === 'ArrowRight') nextPhoto();
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [lightboxIdx, prevPhoto, nextPhoto]);

  return (
    <section className="photo-gallery section" id="photos">
      <div className="container">
        <h2 className="section-title gallery-title">Photos</h2>

        <div className="gallery-masonry">
          {photos.map((photo, idx) => (
            <button
              key={photo.id}
              className="gallery-item"
              onClick={() => setLightboxIdx(idx)}
              aria-label={`Open photo: ${photo.alt}`}
            >
              <img
                src={`/${photo.src}`}
                alt={photo.alt}
                loading="lazy"
                className="gallery-img"
              />
              {photo.caption && (
                <div className="gallery-caption">{photo.caption}</div>
              )}
            </button>
          ))}
        </div>
      </div>

      {lightboxIdx !== null && photos[lightboxIdx] && (
        <div
          className="lightbox"
          role="dialog"
          aria-modal="true"
          aria-label="Photo lightbox"
          onClick={closeLightbox}
        >
          <button className="lightbox-close" onClick={closeLightbox} aria-label="Close">
            <i className="fas fa-times" aria-hidden="true" />
          </button>
          <button
            className="lightbox-nav prev"
            onClick={e => { e.stopPropagation(); prevPhoto(); }}
            aria-label="Previous photo"
          >
            <i className="fas fa-chevron-left" aria-hidden="true" />
          </button>
          <div className="lightbox-inner" onClick={e => e.stopPropagation()}>
            <img
              src={`/${photos[lightboxIdx].src}`}
              alt={photos[lightboxIdx].alt}
              className="lightbox-img"
            />
            {photos[lightboxIdx].caption && (
              <p className="lightbox-caption">{photos[lightboxIdx].caption}</p>
            )}
          </div>
          <button
            className="lightbox-nav next"
            onClick={e => { e.stopPropagation(); nextPhoto(); }}
            aria-label="Next photo"
          >
            <i className="fas fa-chevron-right" aria-hidden="true" />
          </button>
        </div>
      )}
    </section>
  );
};

export default PhotoGallery;
