import React, { useEffect, useState } from 'react';

interface Repo {
  id: number;
  name: string;
  description: string | null;
  html_url: string;
  homepage: string | null;
  language: string | null;
  stargazers_count: number;
  fork: boolean;
  pushed_at: string;
}

const GH_USER = 'dewpoint-av';

// Curated snapshot — used immediately and as the fallback if the GitHub API is unreachable
// (e.g. offline or rate-limited). The live fetch below replaces this with the latest repos.
const FALLBACK: Repo[] = [
  {
    id: 1, name: 'JamCanvas',
    description: 'An audio & visual app for Mobile and Desktop — synthesizers, sequencers, and a node-based GLSL sandbox.',
    html_url: 'https://github.com/dewpoint-av/JamCanvas',
    homepage: 'https://jamcanvas-av.vercel.app',
    language: 'C++', stargazers_count: 0, fork: false, pushed_at: '2026-06-30',
  },
  {
    id: 2, name: 'FluidSPH',
    description: 'Real-time fluid solver for TouchDesigner in GLSL + C++, giving input geometry fluid dynamics.',
    html_url: 'https://github.com/dewpoint-av/FluidSPH',
    homepage: null, language: 'GLSL', stargazers_count: 0, fork: false, pushed_at: '2026-06-30',
  },
  {
    id: 3, name: 'AffectorPOP',
    description: 'Custom C++ TouchDesigner plugin — a POP node that applies GPU forces to particle systems.',
    html_url: 'https://github.com/dewpoint-av/AffectorPOP',
    homepage: null, language: 'C++', stargazers_count: 0, fork: false, pushed_at: '2026-06-30',
  },
  {
    id: 4, name: 'dewpoint-av.github.io',
    description: 'Personal website and project hub.',
    html_url: 'https://github.com/dewpoint-av/dewpoint-av.github.io',
    homepage: null, language: 'HTML', stargazers_count: 0, fork: false, pushed_at: '2026-06-12',
  },
];

const LANG_COLOR: Record<string, string> = {
  'C++': '#f34b7d', C: '#555555', GLSL: '#5686a5', TypeScript: '#3178c6',
  JavaScript: '#f1e05a', HTML: '#e34c26', CSS: '#563d7c', Python: '#3572A5',
  Kotlin: '#A97BFF', Swift: '#F05138', Cuda: '#3A4E3A', Shell: '#89e051',
};

// Extra context layered onto sparse GitHub descriptions, keyed by repo name.
const HIGHLIGHTS: Record<string, string[]> = {
  JamCanvas: ['Shared C++ core', 'SDL2 / ImGui · Android NDK · iOS', 'Custom real-time audio engine', 'GLSL render pipeline'],
  FluidSPH: ['SPH solver', 'GLSL compute', 'Neighbor spatial hashing', 'TouchDesigner POPs'],
  AffectorPOP: ['C++ / CUDA', 'GPU particle forces', 'TouchDesigner SDK'],
};

const Projects: React.FC = () => {
  const [repos, setRepos] = useState<Repo[]>(FALLBACK);
  const [live, setLive] = useState(false);

  useEffect(() => {
    let alive = true;
    fetch(`https://api.github.com/users/${GH_USER}/repos?per_page=100&sort=pushed`)
      .then((r) => (r.ok ? r.json() : Promise.reject(r.status)))
      .then((data: Repo[]) => {
        if (!alive || !Array.isArray(data)) return;
        const clean = data
          .filter((r) => !r.fork)
          .sort((a, b) => (b.pushed_at || '').localeCompare(a.pushed_at || ''));
        if (clean.length) {
          setRepos(clean);
          setLive(true);
        }
      })
      .catch(() => {
        /* keep the curated fallback */
      });
    return () => {
      alive = false;
    };
  }, []);

  return (
    <section id="projects" className="section dev-projects">
      <div className="container">
        <h2 className="section-title">Open-Source Projects</h2>
        <p className="dev-projects-sub">
          {live ? 'Pulled live from ' : 'From '}
          <a href={`https://github.com/${GH_USER}`} target="_blank" rel="noopener noreferrer">
            github.com/{GH_USER}
          </a>
        </p>

        <div className="project-grid">
          {repos.map((repo) => (
            <article key={repo.id} className="project-card">
              <div className="project-card-head">
                <h3 className="project-name">
                  <a href={repo.html_url} target="_blank" rel="noopener noreferrer">
                    {repo.name}
                  </a>
                </h3>
                {repo.language && (
                  <span className="lang-badge">
                    <span className="lang-dot" style={{ background: LANG_COLOR[repo.language] || '#888' }} />
                    {repo.language}
                  </span>
                )}
              </div>

              <p className="project-desc">{repo.description || 'No description provided.'}</p>

              {HIGHLIGHTS[repo.name] && (
                <div className="tech-tags">
                  {HIGHLIGHTS[repo.name].map((h, i) => (
                    <span key={i} className="tech-tag">{h}</span>
                  ))}
                </div>
              )}

              <div className="project-links">
                <a href={repo.html_url} target="_blank" rel="noopener noreferrer" className="project-link">
                  <i className="fab fa-github" /> Code
                </a>
                {repo.homepage && (
                  <a
                    href={repo.homepage}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="project-link project-link-live"
                  >
                    <i className="fas fa-external-link-alt" /> Live Demo
                  </a>
                )}
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Projects;
