import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import MusicianSite from './components/MusicianSite';
import Epk from './components/Epk';
import MainSite from './components/MainSite';
import DevResume from './components/DevResume';
import TouchDesigner from './components/TouchDesigner';
import Notebook from './components/Notebook';
import './App.css';

function App() {
  return (
    <HashRouter>
      <Routes>
        <Route path="/" element={<MusicianSite />} />
        <Route path="/epk" element={<Epk />} />
        <Route path="/resume" element={<MainSite />} />
        <Route path="/dev" element={<DevResume />} />
        <Route path="/touchdesigner" element={<TouchDesigner />} />
        <Route path="/notebook" element={<Notebook />} />
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </HashRouter>
  );
}

export default App; 